import json
import traceback
from typing import Any
from pydantic import BaseModel, ValidationError, field_validator
from lfx.custom.custom_component.component import Component
from lfx.io import MessageTextInput, Output
from lfx.schema.message import Message


class PayloadModel(BaseModel):
    name: str
    age: int
    email: str

    @field_validator("age")
    @classmethod
    def age_must_be_positive(cls, v: int) -> int:
        if v <= 0:
            raise ValueError("age deve ser um inteiro positivo")
        return v

    @field_validator("email")
    @classmethod
    def email_must_have_at(cls, v: str) -> str:
        if "@" not in v:
            raise ValueError("email inválido: deve conter '@'")
        return v.lower().strip()


class ValidationOutput(BaseModel):
    success: bool
    data: PayloadModel | None = None
    error: str | None = None
    traceback: str | None = None


class CustomComponent(Component):
    display_name = "JSON Validator"
    description = (
        "Recebe uma string JSON, faz parse com json.loads e valida "
        "o schema com um BaseModel Pydantic. Em sucesso, expõe os campos "
        "individualmente. Em erro, para as branches de dados e emite mensagem de erro."
    )
    documentation: str = "https://docs.langflow.org/components-custom-components"
    icon = "shield-check"
    name = "JsonValidatorComponent"

    inputs = [
        MessageTextInput(
            name="json_string",
            display_name="JSON String",
            info="Cole aqui o JSON a ser validado.",
            tool_mode=True,
        ),
    ]
    outputs = [
        Output(display_name="age",      name="age",      method="build_age",      group_outputs=True),
        Output(display_name="email",    name="email",    method="build_email",    group_outputs=True),
        Output(display_name="name",     name="name",     method="build_name",     group_outputs=True),
        Output(display_name="On Error", name="on_error", method="build_on_error", group_outputs=True),
    ]

    _cache: ValidationOutput | None = None

    def set_attributes(self, parameters: dict) -> None:
        super().set_attributes(parameters)
        self._cache = None

    def validate_json(self) -> ValidationOutput:
        if self._cache is not None:
            return self._cache

        raw: str = self.json_string
        try:
            parsed: Any = json.loads(raw)
        except json.JSONDecodeError as exc:
            self._cache = ValidationOutput(
                success=False,
                error=f"{exc.__class__.__name__}: {exc}",
                traceback=traceback.format_exc(),
            )
            self.status = self._cache
            return self._cache

        try:
            model = PayloadModel(**parsed)
        except ValidationError as exc:
            self._cache = ValidationOutput(
                success=False,
                error=str(exc.errors()),
                traceback=traceback.format_exc(),
            )
            self.status = self._cache
            return self._cache

        self._cache = ValidationOutput(success=True, data=model)
        self.status = self._cache
        return self._cache

    def build_name(self) -> Message:
        result = self.validate_json()
        if not result.success:
            self.stop("name")
            return Message(text="")
        return Message(text=result.data.name)  # ← faltava isso

    def build_age(self) -> Message:
        result = self.validate_json()
        if not result.success:
            self.stop("age")
            return Message(text="")
        return Message(text=str(result.data.age))  # ← faltava isso

    def build_email(self) -> Message:
        result = self.validate_json()
        if not result.success:
            self.stop("email")
            return Message(text="")
        return Message(text=result.data.email)  # ← faltava isso

    def build_on_error(self) -> Message:
        result = self.validate_json()
        if result.success:
            self.stop("on_error")
            return Message(text="")
        return Message(text=f"Erro de validação: {result.error}")
